-- Seed an onboarding example (sv/en/es) into the Onboarding category for new
-- salespeople. Skips any item whose title already exists in the category.
INSERT INTO public.training_items
  (category_id, title, title_en, title_es, body, body_en, body_es, sort_order, is_published)
SELECT cat.id, v.title, v.title_en, v.title_es, v.body, v.body_en, v.body_es, v.ord, true
FROM (VALUES
  ('Välkommen till Applabbet', 'Welcome to Applabbet', 'Bienvenido a Applabbet', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Välkommen till teamet! På Applabbet hjälper vi företag att växa digitalt – vi bygger hemsidor, MVP:er, webb- och mobilappar samt e-handel, och vi driver tillväxt med SEO och GEO (AI-synlighet)."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Din roll som säljare är att hitta företag med ett digitalt behov, förstå deras situation och matcha rätt lösning. Du säljer aldrig ensam – när avtalet är på plats tar vårt team över och bygger."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Den här utbildningen är din verktygslåda: säljprocess, manus, invändningshantering samt priser och paket. Börja här, och återkom ofta."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Welcome to the team! At Applabbet we help companies grow digitally – we build websites, MVPs, web and mobile apps and e-commerce, and we drive growth with SEO and GEO (AI visibility)."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Your role as a salesperson is to find companies with a digital need, understand their situation and match the right solution. You never sell alone – once the agreement is in place, our team takes over and builds."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "This training is your toolbox: sales process, scripts, objection handling, and prices and packages. Start here, and come back often."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "¡Bienvenido al equipo! En Applabbet ayudamos a las empresas a crecer en digital: creamos webs, MVP, aplicaciones web y móviles y e-commerce, e impulsamos el crecimiento con SEO y GEO (visibilidad en IA)."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tu papel como vendedor es encontrar empresas con una necesidad digital, entender su situación y proponer la solución adecuada. Nunca vendes solo: una vez firmado el acuerdo, nuestro equipo toma el relevo y construye."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Esta formación es tu caja de herramientas: proceso de ventas, guiones, manejo de objeciones y precios y paquetes. Empieza aquí y vuelve a menudo."}]}]}$j$::jsonb, 1),
  ('Din första vecka – checklista', 'Your first week – checklist', 'Tu primera semana – lista de tareas', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Dag 1 – Kom igång: Logga in i CRM:t, gå igenom menyn och bekanta dig med Sandbox-fliken där du kan öva utan att något sparas."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Dag 2 – Lär dig erbjudandet: Läs igenom Priser & paket och säljpitcharna. Förstå vad varje paket löser och ungefär vad det kostar."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Dag 3 – Säljprocessen: Läs det genomgångna exemplet under Säljprocess. Öva på manuset för kalla samtal och första mötet högt."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Dag 4 – Invändningar: Gå igenom invändningshanteringen tills du kan svaren i sömnen."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Dag 5 – Skarpt läge: Lägg in dina första leads i CRM:t och boka ditt första möte. Fråga om hjälp – vi finns här."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Day 1 – Get started: Log in to the CRM, go through the menu and get familiar with the Sandbox tab where you can practise without anything being saved."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Day 2 – Learn the offer: Read through Prices & packages and the sales pitches. Understand what each package solves and roughly what it costs."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Day 3 – The sales process: Read the worked example under Sales process. Practise the cold-call and first-meeting scripts out loud."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Day 4 – Objections: Go through objection handling until you know the answers in your sleep."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Day 5 – Go live: Add your first leads to the CRM and book your first meeting. Ask for help – we're here."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Día 1 – Arranca: Inicia sesión en el CRM, recorre el menú y familiarízate con la pestaña Sandbox, donde puedes practicar sin que se guarde nada."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Día 2 – Aprende la oferta: Lee Precios y paquetes y los pitches de ventas. Entiende qué resuelve cada paquete y cuánto cuesta aproximadamente."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Día 3 – El proceso de ventas: Lee el ejemplo guiado en Proceso de ventas. Practica en voz alta los guiones de llamada en frío y de primera reunión."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Día 4 – Objeciones: Repasa el manejo de objeciones hasta que sepas las respuestas de memoria."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Día 5 – A la acción: Añade tus primeros leads al CRM y agenda tu primera reunión. Pide ayuda: estamos aquí."}]}]}$j$::jsonb, 2),
  ('Så jobbar vi i CRM:t', 'How we work in the CRM', 'Cómo trabajamos en el CRM', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "CRM:t är ditt nav. Här lägger du in leads, loggar samtal och möten, skickar mail och följer dina affärer."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Lägg in en lead: Skapa leaden med företagsnamn och kontaktuppgifter så fort du ser en möjlighet. Anteckna din observation direkt."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Jobba leaden: Använd uppgifter och möten för att hålla koll på nästa steg. En lead utan nästa steg dör."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Dina data är dina: Du ser dina egna leads och din egen aktivitet – inte kollegornas. Håll det uppdaterat, det är så vi ser vad som fungerar."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Öva i Sandbox: Osäker på en funktion? Testa i Sandbox-fliken först – där sparas inget."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "The CRM is your hub. Here you add leads, log calls and meetings, send emails and track your deals."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Add a lead: Create the lead with company name and contact details as soon as you spot an opportunity. Note your observation right away."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Work the lead: Use tasks and meetings to keep track of the next step. A lead with no next step dies."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Your data is yours: You see your own leads and your own activity – not your colleagues'. Keep it updated; that's how we see what works."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Practise in Sandbox: Unsure about a feature? Try it in the Sandbox tab first – nothing is saved there."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "El CRM es tu centro de operaciones. Aquí añades leads, registras llamadas y reuniones, envías correos y haces seguimiento de tus operaciones."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Añade un lead: Crea el lead con el nombre de la empresa y los datos de contacto en cuanto detectes una oportunidad. Anota tu observación enseguida."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Trabaja el lead: Usa tareas y reuniones para no perder el siguiente paso. Un lead sin siguiente paso muere."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tus datos son tuyos: Ves tus propios leads y tu propia actividad, no la de tus compañeros. Mantenlo al día; así vemos qué funciona."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Practica en Sandbox: ¿Dudas con una función? Pruébala primero en la pestaña Sandbox: ahí no se guarda nada."}]}]}$j$::jsonb, 3),
  ('Våra tjänster i korthet', 'Our services in brief', 'Nuestros servicios en breve', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Hemsidor: Från landningssida (från 9 000 kr) till företagshemsida (18 000 kr) med eget CMS."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "MVP & appar: MVP från 29 000 kr, webbapp från 49 000 kr, mobilapp (iOS + Android) från 79 000 kr."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "E-handel: Egen plattform med eget CMS – Start, Plus och Pro."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tillväxt: SEO från 4 900 kr/mån och GEO (AI-synlighet) från 6 900 kr/mån. Designpartner från 9 000 kr/mån."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Kombinationer: Vi paketerar gärna ihop hemsida + SEO + GEO för kunder som vill växa snabbt. Detaljerna finns under Priser & paket."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Websites: From a landing page (from SEK 9,000) to a business website (SEK 18,000) with its own CMS."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "MVP & apps: MVP from SEK 29,000, web app from SEK 49,000, mobile app (iOS + Android) from SEK 79,000."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "E-commerce: Our own platform with its own CMS – Start, Plus and Pro."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Growth: SEO from SEK 4,900/mo and GEO (AI visibility) from SEK 6,900/mo. Design partner from SEK 9,000/mo."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Combinations: We happily bundle website + SEO + GEO for customers who want to grow fast. The details are under Prices & packages."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Webs: Desde una página de aterrizaje (desde 9 000 SEK) hasta una web corporativa (18 000 SEK) con CMS propio."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "MVP y apps: MVP desde 29 000 SEK, aplicación web desde 49 000 SEK, app móvil (iOS + Android) desde 79 000 SEK."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "E-commerce: Nuestra propia plataforma con CMS propio: Start, Plus y Pro."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Crecimiento: SEO desde 4 900 SEK/mes y GEO (visibilidad en IA) desde 6 900 SEK/mes. Socio de diseño desde 9 000 SEK/mes."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Combinaciones: Empaquetamos con gusto web + SEO + GEO para clientes que quieren crecer rápido. Los detalles están en Precios y paquetes."}]}]}$j$::jsonb, 4)
) AS v(title, title_en, title_es, body, body_en, body_es, ord)
JOIN public.training_categories cat ON cat.slug = 'onboarding'
WHERE NOT EXISTS (
  SELECT 1 FROM public.training_items ti
  WHERE ti.category_id = cat.id AND ti.title = v.title
);
